package com.infy.inventrack.catalog; import com.infy.inventrack.catalog.entity.*; import com.infy.inventrack.catalog.repository.*; import com.infy.inventrack.catalog.service.ProductService; import com.infy.inventrack.common.dto.ProductRequest; import com.infy.inventrack.common.exception.DuplicateResourceException; import org.junit.jupiter.api.Test; import java.math.BigDecimal; import java.util.Optional; import static org.assertj.core.api.Assertions.*; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.*; class ProductServiceTest { ProductRepository products=mock(ProductRepository.class); CategoryRepository categories=mock(CategoryRepository.class); ProductService service=new ProductService(products,categories); @Test void duplicateSkuRejected(){ ProductRequest r=req(); when(products.existsBySku("SKU12300")).thenReturn(true); assertThatThrownBy(()->service.createProduct(r)).isInstanceOf(DuplicateResourceException.class); } @Test void createReturnsMessage(){ ProductRequest r=req(); Category c=new Category(); c.setId(1); c.setName("Electronics"); when(categories.findByNameIgnoreCase("Electronics")).thenReturn(Optional.of(c)); when(products.save(any(Product.class))).thenAnswer(i->i.getArgument(0)); assertThat(service.createProduct(r)).contains("Successfully created"); } ProductRequest req(){ ProductRequest r=new ProductRequest(); r.setProductName("Laptop"); r.setSku("SKU12300"); r.setPrice(new BigDecimal("88999.00")); r.setImageUrl("http://example.com/laptop.jpg"); r.setCategory("Electronics"); r.setDescription("High performance laptop"); r.setBrand("HP"); r.setStockQuantity(50); return r; } }
